package daysix_assign;

public class Charcheck {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		 char ch = '4';
		 
		 Character check=ch;

	        if (Character.isDigit(check)) {
	        	
	            System.out.println("digit");
	        } else {
	        	
	            System.out.println("not digit");
	        }

	}

}
